text:
{
  "formal_minutes": {
    "meeting_title": "UI Theme Package Release Readiness",
    "project_code": "PUBLIC_MEETING_SMOKE",
    "participants": [
      "Minjun",
      "Seoyeon",
      "Doyun",
      "Hara"
    ],
    "confirmed_decisions": [
      {
        "topic": "공개 릴리스 목표 시점",
        "decision": "스모크 테스트 통과를 전제로 금요일 15:00 KST를 공개 릴리스 목표로 한다.",
        "basis": "Doyun이 스모크 테스트 선통과 필요성을 제기했고, 최종 결정으로 정리됨."
      },
      {
        "topic": "packageName mismatch 대응 원칙",
        "decision": "packageName mismatch가 발생하면 먼저 package config를 확인하고, 계약 자체가 잘못된 경우에만 스크립트 검토를 진행한다.",
        "basis": "최종 결정으로 명시됨."
      }
    ],
    "rejected_proposals": [
      {
        "topic": "smoke-theme-pack.mjs 처리 방식",
        "proposal": "packageName mismatch를 무시하도록 smoke-theme-pack.mjs를 변경하자.",
        "result": "거절됨"
      }
    ],
    "internal_stretch_goals": [
      {
        "topic": "수요일 릴리스",
        "detail": "수요일 릴리스 제안이 있었으나 최종 공개 릴리스 결정은 아니며 내부 스트레치 목표에 해당한다."
      },
      {
        "topic": "README 설치 단계 검토",
        "detail": "가능하면 목요일까지 검토하자는 의견이 있었으나 확정 일정이나 담당자는 정해지지 않았다."
      }
    ],
    "non_decisions": [
      {
        "topic": "README install steps 검토",
        "status": "필요성은 언급되었으나 담당자 미지정, 확정 결정 아님"
      },
      {
        "topic": "수요일 목표를 릴리스 노트에 기재할지 여부",
        "status": "답이 나지 않음"
      }
    ],
    "risks": [
      {
        "risk": "잘못된 tarball 경로로 인해 릴리스가 지연될 수 있음"
      },
      {
        "risk": "README 설치 단계가 오래되었으면 릴리스 노트가 사용자를 오도할 수 있음"
      }
    ],
    "open_questions": [
      {
        "question": "최종 릴리스 승인 권한자는 누구인가?"
      },
      {
        "question": "내부 수요일 스트레치 목표를 릴리스 노트에 언급해야 하는가?"
      }
    ]
  },
  "action_items": [
    {
      "owner": "Minjun",
      "task": "금요일 10:00 KST까지 스모크 테스트를 재실행하고 결과를 공유한다.",
      "due": "금요일 10:00 KST",
      "status": "확정",
      "source_certainty": "confirmed"
    },
    {
      "owner": "Doyun",
      "task": "금요일 12:00 KST까지 action_items.md에 실패 트리아지 노트를 작성한다.",
      "due": "금요일 12:00 KST",
      "status": "확정",
      "source_certainty": "confirmed"
    },
    {
      "owner": "Hara",
      "task": "Minjun의 스모크 결과 공유 이후 생성된 tarball 경로를 확인한다.",
      "due": "미정",
      "status": "확정",
      "source_certainty": "confirmed"
    },
    {
      "owner": null,
      "task": "README install steps를 가능하면 목요일까지 검토한다.",
      "due": "목요일 가능 시점",
      "status": "미배정",
      "source_certainty": "tentative"
    }
  ],
  "followup_note": {
    "check_next": [
      "Minjun의 스모크 테스트 결과 통과 여부를 확인한다.",
      "스모크 실패 시 Doyun의 실패 트리아지 노트가 action_items.md에 반영되었는지 확인한다.",
      "스모크 결과 공유 후 Hara의 tarball 경로 확인 결과를 점검한다.",
      "README install steps 검토 담당자 지정 필요 여부를 확인한다.",
      "최종 릴리스 승인 권한자에 대한 답변 확보 여부를 확인한다.",
      "릴리스 노트에 내부 수요일 스트레치 목표를 언급할지 결정되었는지 확인한다."
    ],
    "do_not_invent": [
      "고객명 또는 외부 파트너",
      "예산 정보",
      "보안 사고",
      "프로덕션 장애",
      "법무 승인 요건",
      "미지정 담당자",
      "명시되지 않은 마감일"
    ]
  },
  "non_invention_rules": [
    "회의 메모에 없는 고객, 외부 파트너, 예산, 보안, 장애, 법무 사실을 추가하지 않는다.",
    "확정되지 않은 제안은 결정사항으로 승격하지 않는다.",
    "내부 스트레치 목표와 확정 공개 릴리스 목표를 구분한다.",
    "담당자나 마감이 명시되지 않은 항목은 임의로 채우지 않는다.",
    "거절된 제안은 실행 계획처럼 기록하지 않는다.",
    "열린 질문은 답이 없는 상태로 유지하고 추정으로 닫지 않는다."
  ]
}
